#include <bits/stdc++.h>
using namespace std;
int pos,minuss,n,pluss,ans=0;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int t;
		cin>>t;
		ans++;
		if(t>0)
		{
			pluss+=t;
			if(pluss>=minuss&&minuss!=0)
			{
				pluss-=minuss;
                minuss=0;
				ans+=((i-pos)*2);
			}
		}
		else
		{
            t=-t;
			if(t<=pluss)
			{
				pluss-=t;
			}
			else
			{
				if(minuss==0) pos=i;
				minuss+=t;
			}
		}
	}
	cout<<ans;
	return 0;
}
